import { Rewrite } from '@rewritetoday/sdk';

const rewrite = new Rewrite(process.env.REWRITE_API_KEY!);

const { data, error, cursor } = await rewrite.logs.list({
  method: 'POST',
  endpoint: '/messages',
  status: 200,
  limit: 25,
});

if (error) throw error;

